class Solution:
    def sortString(self, s: str) -> str:
        result = []
        s_count = {}
        for char in s:
            if char in s_count:
                s_count[char] += 1
            else:
                s_count[char] = 1

        while s_count:
            # Step 1-3: append smallest character
            sorted_keys = sorted(s_count.keys())
            for key in sorted_keys:
                result.append(key)
                s_count[key] -= 1
                if s_count[key] == 0:
                    del s_count[key]

            # Step 4-6: append largest character
            sorted_keys = sorted(s_count.keys(), reverse=True)
            for key in sorted_keys:
                result.append(key)
                s_count[key] -= 1
                if s_count[key] == 0:
                    del s_count[key]

        return ''.join(result)
```
